INSERT INTO curso (id,titulo,resumo,descricao,nivel,categoria,duracao_min,ordem,publicado) VALUES ('a1000000-0000-4000-8000-000000000026','Módulo 26, Cuide do Seu Aquário como um Profissional','Eleve o cuidado do seu próprio sistema ao nível profissional: método, registro, diagnóstico e autonomia.','Como aplicar rigor profissional no seu próprio aquário ou lago: mentalidade, rotina, checklists, registro no Care, interpretação de parâmetros, prevenção e quando acionar a Aqualife.','avancado','Trilha Bônus · Aquarista Profissional',60,26,true);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2260000-0000-4000-8000-000000000001','a1000000-0000-4000-8000-000000000026','Mentalidade profissional','<p>Cuidar do seu aquário "como um profissional" é uma questão de <b>método, não de sorte</b>. O aquarista avançado não reage a crises: ele observa, mede, registra e antecipa, tratando o próprio sistema com o mesmo rigor de um laboratório.</p>
<p>Essa mentalidade é o que separa o aquário que "às vezes dá certo" do aquário estável por anos.</p>
<figure><svg viewBox="0 0 640 164" xmlns="http://www.w3.org/2000/svg">
<rect x="0" y="0" width="640" height="164" rx="14" fill="#F6F9FB"/><rect x="20" y="30" width="104" height="104" rx="20" fill="#0E7490"/>
<text x="72" y="100" text-anchor="middle" font-size="52">🧠</text>
<text x="150" y="40" font-family="Inter,sans-serif" font-weight="800" font-size="20" fill="#0B2A3A">Mentalidade profissional</text>
<circle cx="160" cy="72" r="6" fill="#0E7490"/><text x="178" y="77" font-family="Inter,sans-serif" font-size="15" fill="#334155">Método no lugar de sorte</text><circle cx="160" cy="112" r="6" fill="#22C55E"/><text x="178" y="117" font-family="Inter,sans-serif" font-size="15" fill="#334155">Observar, medir, registrar</text><circle cx="160" cy="152" r="6" fill="#EAB308"/><text x="178" y="157" font-family="Inter,sans-serif" font-size="15" fill="#334155">Antecipar em vez de reagir</text>
</svg></figure>
<div class="destaque">💡 <b>Ponto-chave:</b> Profissionalismo no seu aquário não é ter equipamento caro, é ter processo: rotina, registro e decisões baseadas em dados.</div>',1);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2260000-0000-4000-8000-000000000002','a1000000-0000-4000-8000-000000000026','Sua rotina e cronograma','<p>O sistema estável nasce de uma <b>rotina</b>: tarefas diárias (observar peixes, conferir temperatura), semanais (testes, TPA) e mensais (limpeza de filtros, revisão de equipamentos), cada uma com sua frequência.</p>
<p>Transformar "cuidar quando lembra" em cronograma é o que previne problemas em vez de apagar incêndios.</p>
<figure><svg viewBox="0 0 640 164" xmlns="http://www.w3.org/2000/svg">
<rect x="0" y="0" width="640" height="164" rx="14" fill="#F6F9FB"/><rect x="20" y="30" width="104" height="104" rx="20" fill="#0E7490"/>
<text x="72" y="100" text-anchor="middle" font-size="52">📅</text>
<text x="150" y="40" font-family="Inter,sans-serif" font-weight="800" font-size="20" fill="#0B2A3A">Rotina e cronograma</text>
<circle cx="160" cy="72" r="6" fill="#0E7490"/><text x="178" y="77" font-family="Inter,sans-serif" font-size="15" fill="#334155">Diário, semanal, mensal</text><circle cx="160" cy="112" r="6" fill="#22C55E"/><text x="178" y="117" font-family="Inter,sans-serif" font-size="15" fill="#334155">Previsível e constante</text><circle cx="160" cy="152" r="6" fill="#EAB308"/><text x="178" y="157" font-family="Inter,sans-serif" font-size="15" fill="#334155">Previne, não remedia</text>
</svg></figure>
<div class="destaque">💡 <b>Ponto-chave:</b> Um bom aquário é rotina, não reação. O cronograma é o que mantém a estabilidade entre uma semana e outra.</div>',2);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2260000-0000-4000-8000-000000000003','a1000000-0000-4000-8000-000000000026','Checklists pessoais','<p>Um <b>checklist</b> garante que nada importante seja esquecido na sua manutenção: verificar equipamentos, testar parâmetros, fazer a TPA e registrar tudo. Nada fica ao acaso ou à memória.</p>
<p>Além de organizar, o checklist cria <b>histórico</b>: você passa a saber exatamente o que fez e quando.</p>
<figure><svg viewBox="0 0 640 115" xmlns="http://www.w3.org/2000/svg"><rect x="0" y="0" width="640" height="115" rx="14" fill="#F6F9FB"/><line x1="110" y1="46" x2="530" y2="46" stroke="#CBD5E1" stroke-width="3"/><circle cx="110" cy="46" r="20" fill="#0E7490"/><text x="110" y="53" text-anchor="middle" font-family="Inter,sans-serif" font-weight="800" font-size="18" fill="#fff">1</text><text x="110" y="92" text-anchor="middle" font-family="Inter,sans-serif" font-size="12" fill="#334155">Equipamentos</text><circle cx="250" cy="46" r="20" fill="#0E7490"/><text x="250" y="53" text-anchor="middle" font-family="Inter,sans-serif" font-weight="800" font-size="18" fill="#fff">2</text><text x="250" y="92" text-anchor="middle" font-family="Inter,sans-serif" font-size="12" fill="#334155">Parâmetros</text><circle cx="390" cy="46" r="20" fill="#0E7490"/><text x="390" y="53" text-anchor="middle" font-family="Inter,sans-serif" font-weight="800" font-size="18" fill="#fff">3</text><text x="390" y="92" text-anchor="middle" font-family="Inter,sans-serif" font-size="12" fill="#334155">TPA</text><circle cx="530" cy="46" r="20" fill="#0E7490"/><text x="530" y="53" text-anchor="middle" font-family="Inter,sans-serif" font-weight="800" font-size="18" fill="#fff">4</text><text x="530" y="92" text-anchor="middle" font-family="Inter,sans-serif" font-size="12" fill="#334155">Registro</text></svg></figure>
<div class="destaque">💡 <b>Ponto-chave:</b> O checklist é o que separa o aquarista metódico do improvisado: mesmo cansado, você não esquece um passo crítico.</div>',3);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2260000-0000-4000-8000-000000000004','a1000000-0000-4000-8000-000000000026','Registro e histórico no Care','<p>O <b>registro</b> é o coração do cuidado profissional: anotar cada teste e cada intervenção transforma leituras soltas em <b>tendências</b>. É assim que você percebe um problema chegando antes dele estourar.</p>
<p>O <b>Aqualife Care</b> é a sua ferramenta central para isso: registra os parâmetros do seu aquário, guarda o histórico e mostra a evolução da saúde ao longo do tempo.</p>
<figure><svg viewBox="0 0 640 164" xmlns="http://www.w3.org/2000/svg">
<rect x="0" y="0" width="640" height="164" rx="14" fill="#F6F9FB"/><rect x="20" y="30" width="104" height="104" rx="20" fill="#0E7490"/>
<text x="72" y="100" text-anchor="middle" font-size="52">📊</text>
<text x="150" y="40" font-family="Inter,sans-serif" font-weight="800" font-size="20" fill="#0B2A3A">Registro e histórico</text>
<circle cx="160" cy="72" r="6" fill="#0E7490"/><text x="178" y="77" font-family="Inter,sans-serif" font-size="15" fill="#334155">De leituras soltas a tendências</text><circle cx="160" cy="112" r="6" fill="#22C55E"/><text x="178" y="117" font-family="Inter,sans-serif" font-size="15" fill="#334155">Enxergue o problema chegando</text><circle cx="160" cy="152" r="6" fill="#0B2A3A"/><text x="178" y="157" font-family="Inter,sans-serif" font-size="15" fill="#334155">O Care guarda tudo por você</text>
</svg></figure>
<a class="aquabook" href="https://app.aqualifeaquarismo.com/entrar.html">🩺 Registrar e acompanhar os seus aquários no Care</a>',4);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2260000-0000-4000-8000-000000000005','a1000000-0000-4000-8000-000000000026','Interpretar seus parâmetros','<p>O aquarista avançado não só <b>mede</b>, ele <b>interpreta</b>: lê os parâmetros em conjunto, entende as interações (como pH e amônia, KH e pH) e traduz tudo em decisões priorizadas para o próprio sistema.</p>
<p>É o que separa "ver um número" de "entender o que ele significa e o que fazer".</p>
<figure><svg viewBox="0 0 620 150" xmlns="http://www.w3.org/2000/svg">
<rect x="0" y="0" width="620" height="150" rx="14" fill="#F6F9FB"/><rect x="20" y="20" width="580" height="110" rx="14" fill="#fff" stroke="#E2E8F0"/><rect x="20" y="20" width="9" height="110" rx="4" fill="#EAB308"/>
<text x="48" y="58" font-family="Inter,sans-serif" font-weight="800" font-size="20" fill="#0B2A3A">KH x pH</text>
<text x="48" y="86" font-family="Inter,sans-serif" font-size="15" fill="#64748B">Leitura: <tspan font-weight="700" fill="#0B2A3A">KH 1 dKH · pH instável</tspan></text>
<rect x="430" y="40" width="150" height="36" rx="18" fill="#EAB308"/><text x="505" y="64" text-anchor="middle" font-family="Inter,sans-serif" font-weight="800" font-size="15" fill="#fff">Prioridade</text>
<line x1="48" y1="100" x2="572" y2="100" stroke="#E2E8F0"/><text x="48" y="121" font-family="Inter,sans-serif" font-size="14" fill="#334155">➡ Decisão: <tspan font-weight="700">Corrigir o KH primeiro estabiliza o pH</tspan></text>
</svg></figure>
<div class="destaque">💡 <b>Ponto-chave:</b> Diagnosticar é priorizar. Nem todo desvio tem o mesmo peso: resolva primeiro a causa raiz, não o sintoma.</div>',5);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2260000-0000-4000-8000-000000000006','a1000000-0000-4000-8000-000000000026','Kit do aquarista avançado','<p>Cuidar bem exige <b>ferramentas confiáveis</b>: testes de qualidade (não só fitas), sifão e baldes dedicados, condicionador, termômetro preciso e ferramentas de limpeza. Instrumentos bons dão dados em que você pode confiar.</p>
<p>Testes ruins levam a decisões erradas: economizar no teste custa caro na água.</p>
<figure><svg viewBox="0 0 640 164" xmlns="http://www.w3.org/2000/svg">
<rect x="0" y="0" width="640" height="164" rx="14" fill="#F6F9FB"/><rect x="20" y="30" width="104" height="104" rx="20" fill="#0E7490"/>
<text x="72" y="100" text-anchor="middle" font-size="52">🧰</text>
<text x="150" y="40" font-family="Inter,sans-serif" font-weight="800" font-size="20" fill="#0B2A3A">Kit avançado</text>
<circle cx="160" cy="72" r="6" fill="#0E7490"/><text x="178" y="77" font-family="Inter,sans-serif" font-size="15" fill="#334155">Testes confiáveis, não só fitas</text><circle cx="160" cy="112" r="6" fill="#22C55E"/><text x="178" y="117" font-family="Inter,sans-serif" font-size="15" fill="#334155">Sifão, baldes, termômetro</text><circle cx="160" cy="152" r="6" fill="#EAB308"/><text x="178" y="157" font-family="Inter,sans-serif" font-size="15" fill="#334155">Bom dado, boa decisão</text>
</svg></figure>
<div class="destaque">💡 <b>Ponto-chave:</b> Seu teste é o seu olho dentro da água. Um kit confiável é o melhor investimento do aquarista sério.</div>',6);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2260000-0000-4000-8000-000000000007','a1000000-0000-4000-8000-000000000026','Diagnóstico e prioridade','<p>Quando algo sai do lugar, o profissional <b>diagnostica com calma</b>: identifica todos os desvios, entende a relação entre eles e ataca primeiro o que é mais grave e mais urgente, sem mudar dez coisas de uma vez.</p>
<p>Intervir demais e ao mesmo tempo é tão perigoso quanto não intervir: você perde a leitura do que funcionou.</p>
<figure><svg viewBox="0 0 620 150" xmlns="http://www.w3.org/2000/svg">
<rect x="0" y="0" width="620" height="150" rx="14" fill="#F6F9FB"/><rect x="20" y="20" width="580" height="110" rx="14" fill="#fff" stroke="#E2E8F0"/><rect x="20" y="20" width="9" height="110" rx="4" fill="#EAB308"/>
<text x="48" y="58" font-family="Inter,sans-serif" font-weight="800" font-size="20" fill="#0B2A3A">Diagnóstico do sistema</text>
<text x="48" y="86" font-family="Inter,sans-serif" font-size="15" fill="#64748B">Leitura: <tspan font-weight="700" fill="#0B2A3A">Nota de saúde 72 · 100</tspan></text>
<rect x="430" y="40" width="150" height="36" rx="18" fill="#EAB308"/><text x="505" y="64" text-anchor="middle" font-family="Inter,sans-serif" font-weight="800" font-size="15" fill="#fff">Atenção</text>
<line x1="48" y1="100" x2="572" y2="100" stroke="#E2E8F0"/><text x="48" y="121" font-family="Inter,sans-serif" font-size="14" fill="#334155">➡ Decisão: <tspan font-weight="700">Estabilizar 1 parâmetro por vez e reavaliar</tspan></text>
</svg></figure>
<div class="destaque">💡 <b>Ponto-chave:</b> Uma mudança de cada vez. Diagnosticar é isolar a causa, agir com critério e reavaliar antes do próximo passo.</div>',7);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2260000-0000-4000-8000-000000000008','a1000000-0000-4000-8000-000000000026','Prevenção e planejamento','<p>O cuidado profissional é <b>preventivo</b>: manter uma reserva de condicionador e insumos, ter um plano de quarentena para novos peixes e conhecer o que fazer numa queda de energia evita que um susto vire tragédia.</p>
<p>Prevenir é sempre mais barato e menos estressante (para você e para os peixes) do que remediar.</p>
<figure><svg viewBox="0 0 640 164" xmlns="http://www.w3.org/2000/svg">
<rect x="0" y="0" width="640" height="164" rx="14" fill="#F6F9FB"/><rect x="20" y="30" width="104" height="104" rx="20" fill="#0E7490"/>
<text x="72" y="100" text-anchor="middle" font-size="52">🛡️</text>
<text x="150" y="40" font-family="Inter,sans-serif" font-weight="800" font-size="20" fill="#0B2A3A">Prevenção</text>
<circle cx="160" cy="72" r="6" fill="#0E7490"/><text x="178" y="77" font-family="Inter,sans-serif" font-size="15" fill="#334155">Reserva de insumos</text><circle cx="160" cy="112" r="6" fill="#22C55E"/><text x="178" y="117" font-family="Inter,sans-serif" font-size="15" fill="#334155">Quarentena para novos peixes</text><circle cx="160" cy="152" r="6" fill="#EAB308"/><text x="178" y="157" font-family="Inter,sans-serif" font-size="15" fill="#334155">Plano para imprevistos</text>
</svg></figure>
<div class="alerta">⚠️ <b>Atenção:</b> A maioria dos desastres em aquário é evitável: quarentena, reserva de insumos e um plano simples poupam muita dor de cabeça.</div>',8);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2260000-0000-4000-8000-000000000009','a1000000-0000-4000-8000-000000000026','Autonomia com limites: quando chamar a Aqualife','<p>Ser avançado inclui <b>reconhecer os próprios limites</b>. Há situações que pedem mão profissional: montagens complexas, doenças persistentes, sistemas grandes, lagos, ou simplesmente quando falta tempo para manter a rotina.</p>
<p>Delegar a manutenção à <b>Aqualife</b> não é fracasso, é garantir que o seu investimento (peixes, corais, plantas) fique em mãos seguras, com laudo e acompanhamento técnico.</p>
<figure><svg viewBox="0 0 640 164" xmlns="http://www.w3.org/2000/svg">
<rect x="0" y="0" width="640" height="164" rx="14" fill="#F6F9FB"/><rect x="20" y="30" width="104" height="104" rx="20" fill="#0E7490"/>
<text x="72" y="100" text-anchor="middle" font-size="52">🩺</text>
<text x="150" y="40" font-family="Inter,sans-serif" font-weight="800" font-size="20" fill="#0B2A3A">Quando chamar a Aqualife</text>
<circle cx="160" cy="72" r="6" fill="#0E7490"/><text x="178" y="77" font-family="Inter,sans-serif" font-size="15" fill="#334155">Doença persistente ou sistema grande</text><circle cx="160" cy="112" r="6" fill="#22C55E"/><text x="178" y="117" font-family="Inter,sans-serif" font-size="15" fill="#334155">Falta de tempo para a rotina</text><circle cx="160" cy="152" r="6" fill="#0B2A3A"/><text x="178" y="157" font-family="Inter,sans-serif" font-size="15" fill="#334155">Seu investimento em mãos seguras</text>
</svg></figure>
<div class="destaque">💡 <b>Ponto-chave:</b> O aquarista maduro sabe a hora de pedir ajuda. A manutenção profissional da Aqualife protege o que você construiu.</div>
<a class="aquabook" href="https://app.aqualifeaquarismo.com/entrar.html">🩺 Conhecer a manutenção profissional da Aqualife</a>',9);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2260000-0000-4000-8000-000000000010','a1000000-0000-4000-8000-000000000026','Evolução contínua','<p>O aquarismo não tem "fim": há sempre uma espécie nova, uma técnica melhor, um upgrade de equipamento. O aquarista profissional <b>nunca para de aprender</b>, estuda, troca com a comunidade e revisa os próprios métodos.</p>
<p>Cada aquário é um professor. Documentar a sua jornada acelera o seu próprio progresso e o de quem aprende com você.</p>
<figure><svg viewBox="0 0 640 115" xmlns="http://www.w3.org/2000/svg"><rect x="0" y="0" width="640" height="115" rx="14" fill="#F6F9FB"/><line x1="110" y1="46" x2="530" y2="46" stroke="#CBD5E1" stroke-width="3"/><circle cx="110" cy="46" r="20" fill="#0E7490"/><text x="110" y="53" text-anchor="middle" font-family="Inter,sans-serif" font-weight="800" font-size="18" fill="#fff">1</text><text x="110" y="92" text-anchor="middle" font-family="Inter,sans-serif" font-size="12" fill="#334155">Estudar</text><circle cx="250" cy="46" r="20" fill="#0E7490"/><text x="250" y="53" text-anchor="middle" font-family="Inter,sans-serif" font-weight="800" font-size="18" fill="#fff">2</text><text x="250" y="92" text-anchor="middle" font-family="Inter,sans-serif" font-size="12" fill="#334155">Aplicar</text><circle cx="390" cy="46" r="20" fill="#0E7490"/><text x="390" y="53" text-anchor="middle" font-family="Inter,sans-serif" font-weight="800" font-size="18" fill="#fff">3</text><text x="390" y="92" text-anchor="middle" font-family="Inter,sans-serif" font-size="12" fill="#334155">Registrar</text><circle cx="530" cy="46" r="20" fill="#0E7490"/><text x="530" y="53" text-anchor="middle" font-family="Inter,sans-serif" font-weight="800" font-size="18" fill="#fff">4</text><text x="530" y="92" text-anchor="middle" font-family="Inter,sans-serif" font-size="12" fill="#334155">Revisar</text></svg></figure>
<div class="destaque">💡 <b>Ponto-chave:</b> O melhor aquarista é o eterno aprendiz. Com registro, comunidade e curiosidade, o seu próximo aquário é sempre melhor que o anterior.</div>',10);
INSERT INTO quiz_pergunta (id,curso_id,pergunta,opcoes,correta,explicacao,ordem) VALUES ('a3260000-0000-4000-8000-000000000001','a1000000-0000-4000-8000-000000000026','Cuidar do seu aquário "como um profissional" significa, acima de tudo:','["Ter o equipamento mais caro","Ter método: rotina, registro e decisões por dados","Trocar a água todo dia","Nunca pedir ajuda"]',1,'Profissionalismo é processo, não preço de equipamento.',1);
INSERT INTO quiz_pergunta (id,curso_id,pergunta,opcoes,correta,explicacao,ordem) VALUES ('a3260000-0000-4000-8000-000000000002','a1000000-0000-4000-8000-000000000026','Registrar os parâmetros ao longo do tempo serve para:','["Enfeitar o app","Transformar leituras soltas em tendências","Substituir a TPA","Baixar o pH"]',1,'O histórico revela o problema antes de ele estourar; o Care guarda isso por você.',2);
INSERT INTO quiz_pergunta (id,curso_id,pergunta,opcoes,correta,explicacao,ordem) VALUES ('a3260000-0000-4000-8000-000000000003','a1000000-0000-4000-8000-000000000026','Ao diagnosticar um problema, o certo é:','["Mudar dez coisas de uma vez","Atacar a causa mais grave primeiro e reavaliar","Ignorar até piorar","Trocar todos os peixes"]',1,'Uma mudança de cada vez preserva a leitura do que funcionou.',3);
INSERT INTO quiz_pergunta (id,curso_id,pergunta,opcoes,correta,explicacao,ordem) VALUES ('a3260000-0000-4000-8000-000000000004','a1000000-0000-4000-8000-000000000026','Quando faz sentido chamar a manutenção profissional da Aqualife?','["Nunca, é sinal de fracasso","Em sistemas grandes, doenças persistentes ou falta de tempo","Só se o aquário quebrar","Apenas para lagos"]',1,'O aquarista maduro reconhece limites e protege o próprio investimento.',4);

-- FIM Trilha Bônus
